const b = $input.first().json.body ?? $input.first().json;
return [{ json: {
  query: b.query ?? 'Research Apple',
  months: parseInt(b.months ?? 6, 10),
  budget_limit: parseInt(b.budget_limit ?? 5, 10)
} }];

const price = $('MCP: get_price_history').item.json;
const info  = $('MCP: get_ticker_info').item.json;
const sym   = $('Resolve Symbol').item.json;
const req   = $('Parse Request').item.json;

const s   = sym.symbol;
const ret = price.period_return;
const dir = ret >= 0 ? String.fromCodePoint(0x25b2) : String.fromCodePoint(0x25bc);
const bar = '='.repeat(60);
const sep = '-'.repeat(50);

const memo = [
  bar,
  '  RESEARCH MEMO: ' + (info.company || s) + ' (' + s + ')',
  bar,
  '  Query:   ' + req.query,
  '  Period:  ' + req.months + ' months',
  '',
  '  Current Price:   $' + price.current_price + '  [1]',
  '  Period Return:   ' + dir + ' ' + Math.abs(ret).toFixed(2) + '%  [1]',
  '  Period High:     $' + price.period_high + '  [1]',
  '  Period Low:      $' + price.period_low + '  [1]',
  '  Avg Volume:      ' + Number(price.avg_volume).toLocaleString() + '  [1]',
  '  Market Cap:      ' + (info.market_cap || 'N/A') + '  [2]',
  '  P/E Ratio:       ' + (info.pe_ratio  || 'N/A') + '  [2]',
  '  Sector:          ' + (info.sector    || 'N/A') + '  [2]',
  '',
  '  Data Sources',
  '  ' + sep,
  '  [1] get_price_history(' + s + ', months=' + req.months + ')',
  '      -> price history, period return, high, low, avg volume',
  '  [2] get_ticker_info(' + s + ')',
  '      -> market cap, P/E ratio, sector',
  '',
  bar
].join('\n');

return [{ json: {
  memo,
  symbol:      s,
  normalized:  sym.normalized,
  raw_output:  sym.raw_output,
  budget_used: 2,
  budget_limit: req.budget_limit
} }];
